/* ── شريط التقدم ── */
function Progress({ step, total, section }) {
  const pct = Math.round(((step + 1) / total) * 100);
  return (
    <div style={{ marginBottom: 22 }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
        <span style={{ color: MUTED, fontSize: 12 }}>{step + 1} / {total}</span>
        <span style={{ color: GOLD, fontSize: 12, fontWeight: 700 }}>{pct}%</span>
      </div>
      <div style={{ height: 6, background: BORDER, borderRadius: 3, overflow: "hidden", marginBottom: 10 }}>
        <div style={{
          height: "100%", width: `${pct}%`, borderRadius: 3,
          background: `linear-gradient(90deg, ${NAVY}, ${GOLD})`,
          transition: "width 0.4s ease",
        }}/>
      </div>
      <div style={{
        display: "inline-block", background: `${GOLD}20`,
        border: `1px solid ${GOLD}55`, borderRadius: 4,
        padding: "3px 10px", color: "#8B6914", fontSize: 11, fontWeight: 700,
      }}>
        {section}
      </div>
    </div>
  );
}

/* ── زر اختيار ── */
function OptionBtn({ label, selected, onClick }) {
  const [hov, setHov] = useState(false);
  return (
    <button onClick={onClick}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        display: "flex", alignItems: "center", gap: 12,
        padding: "13px 16px", borderRadius: 10, width: "100%",
        border: `1.5px solid ${selected ? NAVY : hov ? "#B0BBD4" : BORDER}`,
        borderRight: `${selected ? 4 : 1.5}px solid ${selected ? GOLD : hov ? "#B0BBD4" : BORDER}`,
        background: selected ? "#EDF2FB" : hov ? "#F8FAFF" : WHITE,
        color: selected ? NAVY : "#374151",
        fontWeight: selected ? 700 : 400, fontSize: 14,
        cursor: "pointer", fontFamily: "inherit",
        textAlign: "right", direction: "rtl",
        transition: "all 0.15s",
      }}>
      <span style={{
        width: 20, height: 20, borderRadius: "50%", flexShrink: 0,
        border: `2px solid ${selected ? GOLD : "#C5CEDF"}`,
        background: selected ? GOLD : "transparent",
        display: "flex", alignItems: "center", justifyContent: "center",
        transition: "all 0.15s", marginLeft: 4,
      }}>
        {selected && <span style={{ color: WHITE, fontSize: 10, fontWeight: 900 }}>✓</span>}
      </span>
      {label}
    </button>
  );
}

/* ── شاشة السؤال ── */
function QuizScreen({ questions, answers, onAnswer, onNext, onPrev, step, role }) {
  const q = questions[step];
  const [wilaya, setWilaya] = useState(answers[step] || "");

  useEffect(() => {
    if (q.type === "wilaya") setWilaya(answers[step] || "");
  }, [step]);

  const canNext = q.type === "wilaya" ? wilaya !== "" : answers[step] != null;
  function handleWilaya(v) { setWilaya(v); onAnswer(v); }

  const roleColor = role === "carrier" ? GOLD : BLUE;
  const roleColorText = role === "carrier" ? "#8B6914" : BLUE;

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", padding: "26px 28px" }}>
      <Progress step={step} total={questions.length} section={q.section}/>

      <div style={{
        display: "inline-flex", alignItems: "center", gap: 6,
        background: `${roleColor}1A`, border: `1px solid ${roleColor}55`,
        borderRadius: 4, padding: "4px 12px", marginBottom: 16, width: "fit-content",
      }}>
        <span style={{ fontSize: 14 }}>{role === "carrier" ? "🚛" : "📦"}</span>
        <span style={{ color: roleColorText, fontSize: 11, fontWeight: 700 }}>
          {role === "carrier" ? "ناقل / صاحب شاحنة" : "شاحن / صاحب بضاعة"}
        </span>
      </div>

      <h2 style={{ color: NAVY, fontWeight: 800, fontSize: 19, marginBottom: 20, lineHeight: 1.5 }}>
        {q.q}
      </h2>

      <div style={{ flex: 1, overflowY: "auto" }}>
        {q.type === "wilaya" && (
          <select value={wilaya} onChange={(e) => handleWilaya(e.target.value)} style={{
            width: "100%", padding: "13px 16px", borderRadius: 10,
            border: `1.5px solid ${wilaya ? NAVY : BORDER}`,
            background: WHITE, color: wilaya ? NAVY : MUTED,
            fontSize: 14, fontFamily: "inherit",
            direction: "rtl", outline: "none", cursor: "pointer",
          }}>
            <option value="">— اختر الولاية —</option>
            {WILAYAS.map(w => <option key={w} value={w}>{w}</option>)}
          </select>
        )}

        {q.type === "single" && (
          <div style={{ display: "flex", flexDirection: "column", gap: 9 }}>
            {q.opts.map(opt => (
              <OptionBtn key={opt} label={opt}
                selected={answers[step] === opt}
                onClick={() => onAnswer(opt)}/>
            ))}
          </div>
        )}
      </div>

      <div style={{ display: "flex", gap: 10, marginTop: 20, paddingTop: 16, borderTop: `1px solid ${BORDER}` }}>
        <button onClick={onPrev} style={{
          padding: "13px 18px", borderRadius: 10,
          border: `1px solid ${BORDER}`, background: LIGHT,
          color: "#555", fontSize: 14, fontWeight: 600,
          cursor: "pointer", fontFamily: "inherit",
        }}>→ رجوع</button>
        <button onClick={onNext} disabled={!canNext} style={{
          flex: 1, padding: "13px 20px", borderRadius: 10, border: "none",
          background: canNext ? `linear-gradient(135deg, ${NAVY}, ${NAVY2})` : BORDER,
          color: canNext ? WHITE : MUTED,
          fontSize: 15, fontWeight: 700,
          cursor: canNext ? "pointer" : "not-allowed",
          fontFamily: "inherit", transition: "all 0.2s",
        }}>
          {step === questions.length - 1 ? "التالي ← (بيانات التواصل)" : "التالي ←"}
        </button>
      </div>
    </div>
  );
}

